import type { WithRef } from '@andes/common';
import type { ReactNode, FunctionComponent } from 'react';
import type { ThemeCustomVariantProp } from '@andes/themes';

type BackgroundType = 'basic' | 'complexBackground';

/**
 * @deprecated These colors will be deprecated in a future major version, please use `caution` | `informative` | `inverted` | `negative` | `neutral` | `positive`.
 */
export type DeprecatedBadgeColors =
  | 'accent'
  | 'gray'
  | 'green'
  | 'orange'
  | 'red';

export type BadgeColors =
  | 'caution'
  | 'informative'
  | 'inverted'
  | 'negative'
  | 'neutral'
  | 'positive';

type PillSpecificProps = Record<string, unknown> &
  ThemeCustomVariantProp &
  WithRef<HTMLDivElement> & {
    backgroundType?: BackgroundType;
    /**
     * Custom content (only available for `contentType=text`).
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    children?: ReactNode;

    /**
     * Add custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    className?: string;

    /**
     * Color of the Pill, to show different states.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    color?: BadgeColors | DeprecatedBadgeColors;

    /**
     * Pill content type.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     * @deprecated `contentType` will be deprecated in a future major version, please use `PillIcon` instead of `contentType='icon'` or remove it if you're using `contentType='text'`.
     * @default 'text'
     */
    contentType?: 'icon' | 'text';

    /**
     * Style of the Pill (only available for `contentType=text`).
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     * @default 'loud'
     */
    hierarchy?: 'loud' | 'quiet';

    /**
     * Unique identifier.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    id?: string;

    /**
     * Indicates which corners of the Pill that should be rounded.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     * @default "['top-left', 'top-right', 'bottom-left', 'bottom-right']"
     */
    roundedCorners?: Array<
      'bottom-left' | 'bottom-right' | 'top-left' | 'top-right'
    >;

    /**
     * Allows to use a custom color from secondary palette (only available for `contentType=text`).
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    secondaryColor?: { background: string; text?: string };

    /**
     * Size of the Pill.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     * @default 'large'
     */
    size?: 'large' | 'small';

    /**
     * Label for screen readers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pill-1 | Documentation}
     */
    srLabel?: string;
  };

/**
 * Allows you to make a subtle highlight in the content using color.
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/960764-badge/b/657b41 | UI Specs}
 * @example
 * import { Pill } from '@andes/badge';
 *
 * const MyComponent = () => (
 *   <Pill color='positive'/>
 * );
 */
export const Pill: FunctionComponent<PillSpecificProps>;

type DotSpecificProps = Record<string, unknown> &
  ThemeCustomVariantProp &
  WithRef<HTMLDivElement> & {
    /**
     * Add custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#dot-1 | Documentation}
     */
    className?: string;

    /**
     * Color of the dot, to show different states.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#dot-1 | Documentation}
     */
    color?: BadgeColors | DeprecatedBadgeColors;

    /**
     * Unique identifier.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#dot-1 | Documentation}
     */
    id?: string;

    /**
     * Label for screen readers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#dot-1 | Documentation}
     */
    srLabel?: string;
  };

/**
 * Allows you to make a subtle highlight in the content using color.
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/960764-badge/b/657b41 | UI Specs}
 * @example
 * import { Dot } from '@andes/badge';
 *
 * const MyComponent = () => (
 *   <Dot color='positive'/>
 * );
 */
export const Dot: FunctionComponent<DotSpecificProps>;

type PillIconSpecificProps = Record<string, unknown> &
  ThemeCustomVariantProp &
  WithRef<HTMLDivElement> & {
    backgroundType?: BackgroundType;

    /**
     * Add custom class.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pillicon-1 | Documentation}
     */
    className?: string;

    /**
     * Color of the Pill, to show different states.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pillicon-1 | Documentation}
     */
    color?: BadgeColors | DeprecatedBadgeColors;

    /**
     * Unique identifier.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pillicon-1 | Documentation}
     */
    id?: string;

    /**
     * Size of the Pill.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pillicon-1 | Documentation}
     * @default 'large'
     */
    size?: 'large' | 'small' | 'xsmall';

    /**
     * Label for screen readers.
     *
     * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge#pillicon-1 | Documentation}
     */
    srLabel?: string;
  };

/**
 * Allows you to make a subtle highlight in the content using color.
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/badge | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/960764-badge/b/657b41 | UI Specs}
 * @example
 * import { PillIcon } from '@andes/badge';
 *
 * const MyComponent = () => (
 *   <PillIcon color='positive'/>
 * );
 */
export const PillIcon: FunctionComponent<PillIconSpecificProps>;
